B.LV=new A.ar(B.ij,["acupuncture",u.b,"Acupuncture Training","6 Months","Beginner \u2013 Advanced","Limited Seats","A comprehensive hands-on training program covering traditional acupuncture theory, meridian systems, needle techniques, and clinical applications. Participants will gain the knowledge and practical skills to safely perform acupuncture therapy.",B.IB],t.F)
B.Ir=s(["History & Islamic perspective of Hijama","Dry & wet cupping techniques","Hygiene & sterilisation standards","Point selection for common conditions","Hands-on practical sessions","Certificate upon completion"],t.s)
B.LY=new A.ar(B.ij,["cupping",u.k,"Hijama / Cupping Therapy Training","6 Month","All Levels","Limited Seats","Learn the ancient art of Hijama (wet cupping) and dry cupping therapy in a safe, hygienic, and professional setting. This course covers the historical roots, therapeutic benefits, safety protocols, and step-by-step clinical procedures.",B.Ir],t.F)
B.IF=s(["Functional medicine fundamentals","Nutritional & herbal therapy","Gut health & detox protocols","Patient assessment tools","Evidence-based approach","Certificate upon completion"],t.s)
B.LX=new A.ar(B.ij,["natural",u.H,"Natural & Functional Medicine","6 Months","Intermediate","Limited Seats","Explore the principles of functional and integrative medicine, including nutrition therapy, herbal remedies, detoxification, and lifestyle modification strategies. Designed for healthcare practitioners seeking a holistic approach.",B.IF],t.F)
B.Jb=s(["Detox pathways & physiology","Therapeutic techniques","Diet & lifestyle guidance","Practical demonstrations","Certificate upon completion"],t.s)
B.LW=new A.ar(B.ij,["bio",u.u,"Bio-Purification Therapy Training","6 Months","Beginner","Limited Seats","Master the methods of bio-purification and detoxification therapy. This training covers holistic detox principles, therapeutic protocols, and practical techniques used to cleanse and restore the body naturally.",B.Jb],t.F)
